</div><script>function toggleWishlistDetail(btn, productId) {    const csrfToken = document.querySelector('meta[name="csrf-token"]')?.getAttribute('content') || '';    const icon = document.getElementById('wishlistIcon');    const text = document.getElementById('wishlistText');    btn.disabled = true;    fetch("{{ route('user.wishlists.toggle') }}", {        method: "POST",        headers: {            "X-CSRF-TOKEN": csrfToken,            "Content-Type": "application/json",            "Accept": "application/json"        },        body: JSON.stringify({ product_id: productId })    })    .then(res => res.json())    .then(data => {        if (data.status === 'added') {            icon.setAttribute('fill', 'currentColor');            text.textContent = 'Di Wishlist';            btn.classList.remove('border-slate-200', 'bg-slate-50', 'text-slate-600', 'hover:bg-red-50', 'hover:text-red-600', 'hover:border-red-200');            btn.classList.add('border-red-200', 'bg-red-50', 'text-red-600');        } else {            icon.setAttribute('fill', 'none');            text.textContent = 'Wishlist';            btn.classList.remove('border-red-200', 'bg-red-50', 'text-red-600');            btn.classList.add('border-slate-200', 'bg-slate-50', 'text-slate-600', 'hover:bg-red-50', 'hover:text-red-600', 'hover:border-red-200');        }    })    .catch(() => {})    .finally(() => { btn.disabled = false; });}</script>@endsection